    base_program_id,
    intensity_level,
    duration_weeks,
    variant_name,
    program_category,
    sessions_per_week,
    session_duration_minutes,
    goals,
    workouts
) SELECT
    bp.id,
    'Medium',
    2,
    'Resistance Band Only - 2w 4x/wk',
    'equipment_specific',
    4,
    60,
    ARRAY['Maximize muscle hypertrophy', 'Time under tension']::text[],
    '[]'::jsonb
FROM branded_programs bp
WHERE bp.name = 'Resistance Band Only'
ON CONFLICT DO NOTHING;

